package chi

import (
	"context"
	"net/http"
	"time"
)

// MetricsCollector is the interface used by a Mux to report route hit
// metrics. Implementations can forward RouteMetric data to whatever
// monitoring or observability system the application uses.
type MetricsCollector interface {
	// RecordHit is called after a matched route's handler has finished
	// serving a request.
	RecordHit(ctx context.Context, r *http.Request, duration time.Duration)
}

// RouteMetric contains the data collected for a single request that was
// routed to a matched handler.
type RouteMetric struct {
	// Pattern is the routing pattern that matched the request, e.g. "/users/{id}".
	Pattern string

	// Method is the HTTP method of the request.
	Method string

	// Path is the request URL path that was routed.
	Path string

	// Duration is how long the matched handler took to serve the request.
	Duration time.Duration

	// URLParams are the URL parameters captured while matching the route.
	URLParams RouteParams
}

// SimpleMetricsCollector is a MetricsCollector implementation that invokes a
// user-supplied callback function for each recorded route hit. It's intended
// for basic metric collection scenarios where a full MetricsCollector
// implementation isn't necessary.
type SimpleMetricsCollector struct {
	// Fn is called with the collected RouteMetric for every recorded hit.
	Fn func(RouteMetric)
}

// RecordHit implements the MetricsCollector interface.
func (c *SimpleMetricsCollector) RecordHit(ctx context.Context, r *http.Request, duration time.Duration) {
	if c.Fn == nil {
		return
	}

	rctx, _ := ctx.Value(RouteCtxKey).(*Context)

	metric := RouteMetric{
		Method:  r.Method,
		Path:    r.URL.Path,
		Duration: duration,
	}

	if rctx != nil {
		metric.Pattern = rctx.RoutePattern()
		metric.URLParams = rctx.URLParams
	}

	c.Fn(metric)
}

