package chi

import (
	"net/http"
	"net/http/httptest"
	"testing"
	"time"
)

func TestSimpleMetricsCollectorRecordsHit(t *testing.T) {
	var got RouteMetric
	var calls int

	collector := &SimpleMetricsCollector{
		Fn: func(m RouteMetric) {
			calls++
			got = m
		},
	}

	r := NewMux()
	r.SetMetricsCollector(collector)
	r.Get("/users/{id}", func(w http.ResponseWriter, req *http.Request) {
		time.Sleep(1 * time.Millisecond)
		w.WriteHeader(http.StatusOK)
	})

	ts := httptest.NewServer(r)
	defer ts.Close()

	req := httptest.NewRequest(http.MethodGet, "/users/123", nil)
	w := httptest.NewRecorder()
	r.ServeHTTP(w, req)

	if calls != 1 {
		t.Fatalf("expected RecordHit to be called once, got %d", calls)
	}
	if got.Method != http.MethodGet {
		t.Errorf("expected method %q, got %q", http.MethodGet, got.Method)
	}
	if got.Path != "/users/123" {
		t.Errorf("expected path %q, got %q", "/users/123", got.Path)
	}
	if got.Pattern != "/users/{id}" {
		t.Errorf("expected pattern %q, got %q", "/users/{id}", got.Pattern)
	}
	if got.Duration <= 0 {
		t.Errorf("expected a positive duration, got %v", got.Duration)
	}

	found := false
	for i, key := range got.URLParams.Keys {
		if key == "id" && got.URLParams.Values[i] == "123" {
			found = true
		}
	}
	if !found {
		t.Errorf("expected URLParams to contain id=123, got %+v", got.URLParams)
	}
}

func TestNoMetricsCollectorConfigured(t *testing.T) {
	r := NewMux()
	r.Get("/ping", func(w http.ResponseWriter, req *http.Request) {
		w.WriteHeader(http.StatusOK)
	})

	req := httptest.NewRequest(http.MethodGet, "/ping", nil)
	w := httptest.NewRecorder()
	r.ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Fatalf("expected status 200, got %d", w.Code)
	}
}

func TestMetricsCollectorNotCalledOnNotFound(t *testing.T) {
	var calls int
	collector := &SimpleMetricsCollector{
		Fn: func(m RouteMetric) {
			calls++
		},
	}

	r := NewMux()
	r.SetMetricsCollector(collector)
	r.Get("/ping", func(w http.ResponseWriter, req *http.Request) {
		w.WriteHeader(http.StatusOK)
	})

	req := httptest.NewRequest(http.MethodGet, "/nonexistent", nil)
	w := httptest.NewRecorder()
	r.ServeHTTP(w, req)

	if w.Code != http.StatusNotFound {
		t.Fatalf("expected status 404, got %d", w.Code)
	}
	if calls != 0 {
		t.Fatalf("expected RecordHit not to be called for unmatched routes, got %d calls", calls)
	}
}

